import React, { useRef } from 'react';
import { Container, Typography, Box, Card, CardContent, Chip } from '@mui/material';
import { useNavigate } from 'react-router-dom';
import TrendingUpIcon from '@mui/icons-material/TrendingUp';
import BusinessIcon from '@mui/icons-material/Business';
import EmojiEventsIcon from '@mui/icons-material/EmojiEvents';
import SchoolIcon from '@mui/icons-material/School';
import FitnessCenterIcon from '@mui/icons-material/FitnessCenter';
import AttachMoneyIcon from '@mui/icons-material/AttachMoney';
import PsychologyIcon from '@mui/icons-material/Psychology';
import CheckCircleIcon from '@mui/icons-material/CheckCircle';
import SmartToyIcon from '@mui/icons-material/SmartToy';
import AssessmentIcon from '@mui/icons-material/Assessment';

const C = {
  green: '#478559', greenDark: '#2d5c3d', greenLight: '#5a9e70',
  purple: '#161748', purpleMid: '#232460', greyBlue: '#4f5f76',
  pearl: '#f5f0e8', pearlDark: '#ede5d8', cream: '#faf7f2',
};

function TiltCard({ children, onClick, sx }) {
  const ref = useRef(null);
  const handleMove = (e) => {
    if (!ref.current) return;
    const rect = ref.current.getBoundingClientRect();
    const x = (e.clientX - rect.left) / rect.width - 0.5;
    const y = (e.clientY - rect.top) / rect.height - 0.5;
    ref.current.style.transform = `perspective(600px) rotateY(${x * 8}deg) rotateX(${-y * 8}deg) scale(1.03)`;
    ref.current.style.boxShadow = `${x * -10}px ${y * -10}px 30px rgba(71,133,89,0.2), 0 8px 32px rgba(22,23,72,0.12)`;
  };
  const handleLeave = () => {
    if (!ref.current) return;
    ref.current.style.transform = 'perspective(600px) rotateY(0deg) rotateX(0deg) scale(1)';
    ref.current.style.boxShadow = '0 2px 16px rgba(22,23,72,0.06)';
  };
  return (
    <Card ref={ref} onClick={onClick} onMouseMove={handleMove} onMouseLeave={handleLeave}
      sx={{ cursor: 'pointer', transition: 'transform 0.15s ease, box-shadow 0.15s ease', ...sx }}>
      {children}
    </Card>
  );
}

const sections = [
  { title: 'Business', sub: 'Deep-dive ideas & blueprints', icon: <BusinessIcon />, path: '/business', color: C.green, bg: 'rgba(71,133,89,0.08)', badge: 'Daily' },
  { title: 'Best Idea', sub: 'Top 3 business models', icon: <EmojiEventsIcon />, path: '/best-idea', color: '#b45309', bg: 'rgba(180,83,9,0.08)', badge: 'Hot 🔥' },
  { title: 'Financial', sub: 'Track & link your card', icon: <AttachMoneyIcon />, path: '/financial', color: C.greyBlue, bg: 'rgba(79,95,118,0.08)', badge: 'Smart' },
  { title: 'Mindset', sub: 'Daily mental frameworks', icon: <PsychologyIcon />, path: '/mindset', color: C.purpleMid, bg: 'rgba(35,36,96,0.08)', badge: 'Daily' },
  { title: 'Learning', sub: 'Interactive lessons + quizzes', icon: <SchoolIcon />, path: '/learning', color: '#0369a1', bg: 'rgba(3,105,161,0.08)', badge: 'Interactive' },
  { title: 'Health', sub: 'Workouts + meal plans', icon: <FitnessCenterIcon />, path: '/health', color: '#b91c1c', bg: 'rgba(185,28,28,0.08)', badge: 'Today' },
  { title: 'Check-in', sub: 'Daily reflection', icon: <CheckCircleIcon />, path: '/checkin', color: C.green, bg: 'rgba(71,133,89,0.08)', badge: '' },
  { title: 'Reports', sub: 'Your progress overview', icon: <AssessmentIcon />, path: '/reports', color: C.greyBlue, bg: 'rgba(79,95,118,0.08)', badge: '' },
  { title: 'AI Advisor', sub: 'Personal AI coach', icon: <SmartToyIcon />, path: '/ai', color: C.purpleMid, bg: 'rgba(35,36,96,0.08)', badge: 'AI' },
];

export default function Dashboard() {
  const navigate = useNavigate();
  const today = new Date().toLocaleDateString('en-US', { weekday: 'long', month: 'long', day: 'numeric' });

  return (
    <Container maxWidth="xl" sx={{ py: 2 }}>
      {/* Hero greeting */}
      <Box sx={{
        mb: 5, p: 4, borderRadius: 4,
        background: `linear-gradient(135deg, ${C.purple} 0%, ${C.purpleMid} 50%, ${C.greyBlue} 100%)`,
        position: 'relative', overflow: 'hidden',
        boxShadow: `0 8px 32px rgba(22,23,72,0.25)`,
      }}>
        {/* Decorative circles */}
        <Box sx={{ position: 'absolute', top: -40, right: -40, width: 200, height: 200, borderRadius: '50%', bgcolor: 'rgba(71,133,89,0.15)' }} />
        <Box sx={{ position: 'absolute', bottom: -60, right: 80, width: 150, height: 150, borderRadius: '50%', bgcolor: 'rgba(245,240,232,0.05)' }} />
        <Box sx={{ position: 'relative', zIndex: 1 }}>
          <Typography variant="caption" sx={{ color: 'rgba(245,240,232,0.6)', letterSpacing: 3, textTransform: 'uppercase', fontSize: '0.7rem' }}>
            {today}
          </Typography>
          <Typography variant="h3" fontWeight={800} sx={{ color: C.pearl, mt: 0.5, lineHeight: 1.2 }}>
            Good {new Date().getHours() < 12 ? 'Morning' : new Date().getHours() < 17 ? 'Afternoon' : 'Evening'},
          </Typography>
          <Typography variant="h3" fontWeight={800} sx={{ color: C.greenLight, lineHeight: 1.2 }}>
            Sirawdink 👋
          </Typography>
          <Typography sx={{ color: 'rgba(245,240,232,0.6)', mt: 1.5, maxWidth: 500 }}>
            Your personal OS is ready. Every tool you need to build, grow, and level up — all in one place.
          </Typography>
          <Box sx={{ display: 'flex', gap: 1, mt: 2, flexWrap: 'wrap' }}>
            {['Business Ideas ✓', 'Finance Tracking ✓', 'AI Learning ✓', 'Daily Workouts ✓'].map(tag => (
              <Chip key={tag} label={tag} size="small" sx={{ bgcolor: 'rgba(71,133,89,0.25)', color: C.greenLight, border: '1px solid rgba(71,133,89,0.3)', fontWeight: 600 }} />
            ))}
          </Box>
        </Box>
      </Box>

      {/* Section Grid */}
      <Typography variant="h6" fontWeight={700} sx={{ color: C.greyBlue, mb: 2.5, textTransform: 'uppercase', letterSpacing: 2, fontSize: '0.75rem' }}>
        Your Modules
      </Typography>
      <Box sx={{ display: 'grid', gridTemplateColumns: { xs: '1fr 1fr', sm: 'repeat(3, 1fr)', md: 'repeat(3, 1fr)', lg: 'repeat(3, 1fr)' }, gap: 2 }}>
        {sections.map((s) => (
          <TiltCard key={s.title} onClick={() => navigate(s.path)} sx={{ bgcolor: '#fff' }}>
            <CardContent sx={{ p: 3 }}>
              <Box sx={{ display: 'flex', alignItems: 'flex-start', justifyContent: 'space-between', mb: 2 }}>
                <Box sx={{
                  width: 48, height: 48, borderRadius: 3,
                  bgcolor: s.bg, display: 'flex', alignItems: 'center', justifyContent: 'center',
                  color: s.color,
                }}>
                  {s.icon}
                </Box>
                {s.badge && (
                  <Chip label={s.badge} size="small" sx={{ bgcolor: s.bg, color: s.color, fontWeight: 700, fontSize: '0.65rem' }} />
                )}
              </Box>
              <Typography fontWeight={700} sx={{ color: C.purple, mb: 0.5 }}>{s.title}</Typography>
              <Typography variant="caption" sx={{ color: C.greyBlue }}>{s.sub}</Typography>
            </CardContent>
          </TiltCard>
        ))}
      </Box>

      {/* Quick stats row */}
      <Box sx={{ mt: 4, display: 'flex', gap: 2, flexWrap: 'wrap' }}>
        {[
          { label: 'Ideas Available', value: '4+', color: C.green },
          { label: 'Learning Courses', value: '3', color: '#0369a1' },
          { label: 'Workout Days', value: '7', color: '#b91c1c' },
          { label: 'AI Ready', value: '✓', color: C.purpleMid },
        ].map(s => (
          <Box key={s.label} sx={{
            flex: 1, minWidth: 120, p: 2.5, borderRadius: 3,
            bgcolor: '#fff', border: '1px solid rgba(71,133,89,0.12)',
            boxShadow: '0 2px 8px rgba(22,23,72,0.04)',
            textAlign: 'center',
          }}>
            <Typography variant="h4" fontWeight={800} sx={{ color: s.color }}>{s.value}</Typography>
            <Typography variant="caption" sx={{ color: C.greyBlue, fontWeight: 600 }}>{s.label}</Typography>
          </Box>
        ))}
      </Box>
    </Container>
  );
}
